import React, { useState } from 'react';
import { Subject, ConsultationRequest, TutoringPlan } from '../types';
import { generateStudyPlan } from '../services/geminiService';

const ConsultationForm: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [plan, setPlan] = useState<TutoringPlan | null>(null);
  const [formData, setFormData] = useState<ConsultationRequest>({
    parentName: '',
    email: '',
    studentName: '',
    subject: Subject.MATHS,
    description: ''
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const generatedPlan = await generateStudyPlan(formData);
      setPlan(generatedPlan);
    } catch (err) {
      alert("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  if (plan) {
    return (
      <div className="bg-white p-8 rounded-2xl shadow-2xl border border-indigo-100 max-w-2xl mx-auto animate-in fade-in zoom-in duration-500">
        <div className="flex items-center space-x-3 mb-6">
          <div className="bg-green-100 p-2 rounded-full">
            <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-gray-900">Custom Tutoring Plan for {formData.studentName}</h2>
        </div>
        <p className="text-gray-600 mb-6 italic">"{plan.summary}"</p>
        <div className="space-y-4 mb-8">
          <h3 className="font-bold text-gray-900 flex items-center space-x-2">
            <span>Focus Areas</span>
          </h3>
          <ul className="space-y-2">
            {plan.recommendations.map((rec, i) => (
              <li key={i} className="flex items-start space-x-3 text-gray-700">
                <span className="mt-1.5 w-1.5 h-1.5 bg-indigo-500 rounded-full flex-shrink-0"></span>
                <span>{rec}</span>
              </li>
            ))}
          </ul>
        </div>
        <div className="bg-indigo-50 p-4 rounded-xl mb-8">
          <p className="text-indigo-900 font-semibold">Suggested Frequency: {plan.estimatedDuration}</p>
        </div>
        <div className="flex space-x-4">
          <button 
            onClick={() => setPlan(null)}
            className="flex-1 py-3 bg-white border border-gray-200 text-gray-700 rounded-xl font-bold hover:bg-gray-50 transition"
          >
            Edit Details
          </button>
          <button 
            className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-200"
            onClick={() => alert("Registration complete! A coordinator will contact you shortly.")}
          >
            Confirm & Assign Teacher
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white p-8 rounded-2xl shadow-2xl border border-gray-100 max-w-2xl mx-auto">
      <div className="text-center mb-8">
        <h2 className="text-3xl font-bold text-gray-900 mb-2">Request a Consultation</h2>
        <p className="text-gray-600">Tell us about your child's challenges, and our AI-Assistant will draft a specialized plan.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Your Name</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
              placeholder="Full Name"
              value={formData.parentName}
              onChange={(e) => setFormData({...formData, parentName: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Email Address</label>
            <input 
              required
              type="email" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
              placeholder="email@example.com"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Student Name</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
              placeholder="First Name"
              value={formData.studentName}
              onChange={(e) => setFormData({...formData, studentName: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Subject of Concern</label>
            <select 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition"
              value={formData.subject}
              onChange={(e) => setFormData({...formData, subject: e.target.value as Subject})}
            >
              {Object.values(Subject).map(sub => <option key={sub} value={sub}>{sub}</option>)}
            </select>
          </div>
        </div>

        <div>
          <label className="block text-sm font-semibold text-gray-700 mb-2">Specific Challenges</label>
          <textarea 
            className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none transition h-32"
            placeholder="e.g., Struggling with Calculus, needs help building confidence, or foundational gaps in physics..."
            value={formData.description}
            onChange={(e) => setFormData({...formData, description: e.target.value})}
          ></textarea>
        </div>

        <button 
          disabled={loading}
          type="submit" 
          className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold text-lg hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 disabled:opacity-50 flex items-center justify-center space-x-3"
        >
          {loading ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>Analyzing Needs...</span>
            </>
          ) : (
            <span>Request Personalized Plan</span>
          )}
        </button>
      </form>
    </div>
  );
};

export default ConsultationForm;

