import { GoogleGenAI, Type } from "@google/genai";
import { ConsultationRequest } from "../types.ts";

export const generateStudyPlan = async (request: ConsultationRequest) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    A parent named ${request.parentName} is seeking help for their child ${request.studentName}, who is in grade 7-12 and struggling with ${request.subject}. 

    CRITICAL CONTEXT: The student is located in ${request.location}. 
    Please ensure the plan accounts for the educational system typical of this region (e.g., WAEC/NECO for West Africa, Common Core for USA, GCSE for UK, etc.).

    Additional context from parent: ${request.description}.

    Our tutoring service focuses on:
    1. Reinforcing the existing school curriculum (we do not teach something different).
    2. Holistic growth (discipline, responsibility, character, God-fearing values).
    3. Building confidence and foundational skills.

    Please provide a structured tutoring plan in JSON format. The summary should acknowledge their region's specific academic standards.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "A brief professional summary of the child's academic needs, acknowledging their specific region's education system." },
            recommendations: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3-5 specific tutoring steps or focus areas tailored to their curriculum and location."
            },
            estimatedDuration: { type: Type.STRING, description: "Suggested hours per week." }
          },
          required: ["summary", "recommendations", "estimatedDuration"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

